define(["jquery"],function($){function init(){var start=Date.now();var $timer=$("#kopere_dashboard-timer");var $read=$("#kopere_dashboard-readseconds");var $btn=$("#kopere_dashboard-accept-btn");if(!$timer.length||!$read.length||!$btn.length){return}window.setInterval(function(){var seconds=Math.floor((Date.now()-start)/1e3);$timer.text(seconds);$read.val(seconds)},1e3);$("#kopere_dashboard-contract-accept-form").on("submit",function(){try{var s=Math.floor((Date.now()-start)/1e3);$read.val(s)}catch(e){}$btn.prop("disabled",true);$btn.text(M.util.get_string("js_processing","local_kopere_dashboard"))})}return{init:init}});